"use client";

import { motion } from "framer-motion";
import { useState } from "react";
import { cn } from "@/lib/utils";

interface HyperTextProps {
  text: string;
  className?: string;
  href?: string;
  onClick?: () => void;
}

export function HyperText({ text, className, href, onClick }: HyperTextProps) {
  const [isHovered, setIsHovered] = useState(false);

  const letters = text.split("");

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.05,
      },
    },
  };

  const letterVariants = {
    hidden: { 
      y: 50,
      opacity: 0,
      rotateX: -90,
    },
    visible: {
      y: 0,
      opacity: 1,
      rotateX: 0,
      transition: {
        type: "spring",
        stiffness: 300,
        damping: 20,
      },
    },
  };

  const hoverVariants = {
    scale: 1.1,
    transition: {
      type: "spring",
      stiffness: 400,
      damping: 17,
    },
  };

  const content = (
    <motion.div
      className={cn(
        "inline-block cursor-pointer relative",
        className
      )}
      variants={containerVariants}
      initial="hidden"
      animate="visible"
      whileHover={hoverVariants}
      onHoverStart={() => setIsHovered(true)}
      onHoverEnd={() => setIsHovered(false)}
      onClick={onClick}
    >
      <div className="flex">
        {letters.map((letter, index) => (
          <motion.span
            key={index}
            className="inline-block relative"
            variants={letterVariants}
            whileHover={{
              y: -10,
              color: "#3b82f6",
              textShadow: "0 0 20px rgba(59, 130, 246, 0.8)",
              transition: {
                type: "spring",
                stiffness: 500,
                damping: 15,
              },
            }}
            style={{
              perspective: "1000px",
              transformStyle: "preserve-3d",
            }}
          >
            {letter === " " ? "\u00A0" : letter}
          </motion.span>
        ))}
      </div>
      {isHovered && (
        <motion.div
          className="absolute bottom-0 left-0 right-0 h-1 bg-gradient-to-r from-blue-500 via-purple-500 to-pink-500"
          initial={{ scaleX: 0 }}
          animate={{ scaleX: 1 }}
          exit={{ scaleX: 0 }}
          transition={{ duration: 0.3 }}
        />
      )}
    </motion.div>
  );

  if (href) {
    return (
      <a href={href} className="no-underline">
        {content}
      </a>
    );
  }

  return content;
}

