"use client";

import { useEffect, useRef, useState } from "react";
import { motion } from "framer-motion";
import { cn } from "@/lib/utils";

interface AnimatedShaderHeroProps {
  children?: React.ReactNode;
  className?: string;
}

export function AnimatedShaderHero({
  children,
  className,
}: AnimatedShaderHeroProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let animationId: number;
    let time = 0;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    resize();
    window.addEventListener("resize", resize);

    const animate = () => {
      time += 0.01;
      
      const gradient = ctx.createLinearGradient(
        0,
        0,
        canvas.width,
        canvas.height
      );

      gradient.addColorStop(0, `hsl(${(time * 50) % 360}, 70%, 50%)`);
      gradient.addColorStop(0.5, `hsl(${(time * 50 + 60) % 360}, 70%, 50%)`);
      gradient.addColorStop(1, `hsl(${(time * 50 + 120) % 360}, 70%, 50%)`);

      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Mouse pozisyonuna göre ek efekt
      const mouseX = mousePosition.x;
      const mouseY = mousePosition.y;
      
      if (mouseX > 0 && mouseY > 0) {
        const radialGradient = ctx.createRadialGradient(
          mouseX,
          mouseY,
          0,
          mouseX,
          mouseY,
          300
        );
        radialGradient.addColorStop(0, "rgba(255, 255, 255, 0.1)");
        radialGradient.addColorStop(1, "rgba(0, 0, 0, 0)");
        
        ctx.fillStyle = radialGradient;
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      }

      animationId = requestAnimationFrame(animate);
    };

    animate();

    return () => {
      window.removeEventListener("resize", resize);
      cancelAnimationFrame(animationId);
    };
  }, [mousePosition]);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    setMousePosition({ x: e.clientX, y: e.clientY });
  };

  return (
    <div
      className={cn(
        "relative w-full h-screen overflow-hidden",
        className
      )}
      onMouseMove={handleMouseMove}
    >
      <canvas
        ref={canvasRef}
        className="absolute inset-0 w-full h-full"
        style={{ mixBlendMode: "multiply" }}
      />
      <div className="relative z-10 w-full h-full flex items-center justify-center">
        {children}
      </div>
    </div>
  );
}

